## Service Worker: Asset Caching
```typescript
// src/sw.ts
/// <reference lib="webworker" />
declare const self: ServiceWorkerGlobalScope;

const CACHE_NAME = 'frankensqlite-v1';

// Assets that should be cached on install
const PRECACHE_ASSETS = [
  '/',
  '/index.html',
  '/frankensqlite_bg.wasm',      // WASM binary (largest asset, cache first!)
  '/frankensqlite.js',
  '/frankensqlite.worker.js',
];

// Install: precache critical assets
self.addEventListener('install', (event) => {
  console.log('[SW] Installing, precaching assets...');
  event.waitUntil(
    caches.open(CACHE_NAME).then(async (cache) => {
      for (const url of PRECACHE_ASSETS) {
        try {
          await cache.add(url);
          console.log(`[SW] Cached: ${url}`);
        } catch (err) {
          console.warn(`[SW] Failed to cache: ${url}`, err);
        }
      }
      console.log(`[SW] Precache complete (${PRECACHE_ASSETS.length} assets)`);
    })
  );
  self.skipWaiting();
});

// Activate: clean old caches
self.addEventListener('activate', (event) => {
  console.log('[SW] Activating...');
  event.waitUntil(
    caches.keys().then(keys =>
      Promise.all(
        keys
          .filter(key => key !== CACHE_NAME)
          .map(key => {
            console.log(`[SW] Deleting old cache: ${key}`);
            return caches.delete(key);
          })
      )
    ).then(() => self.clients.claim())
  );
});

// Fetch: cache-first for WASM/JS, network-first for API
self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // WASM binary: cache-first (large, rarely changes)
  if (url.pathname.endsWith('.wasm')) {
    event.respondWith(cacheFirst(event.request));
    return;
  }

  // JS/CSS: stale-while-revalidate
  if (url.pathname.match(/\.(js|css)$/)) {
    event.respondWith(staleWhileRevalidate(event.request));
    return;
  }

  // HTML: network-first with cache fallback
  if (event.request.headers.get('accept')?.includes('text/html')) {
    event.respondWith(networkFirst(event.request));
    return;
  }

  // Default: network only
  event.respondWith(fetch(event.request));
});
```

## Cache Strategies
```typescript
// src/cache-strategies.ts
async function cacheFirst(request: Request): Promise<Response> {
  const cached = await caches.match(request);
  if (cached) {
    console.log(`[SW] Cache hit: ${request.url}`);
    return cached;
  }
  console.log(`[SW] Cache miss, fetching: ${request.url}`);
  const response = await fetch(request);
  if (response.ok) {
    const cache = await caches.open(CACHE_NAME);
    cache.put(request, response.clone());
  }
  return response;
}

async function staleWhileRevalidate(request: Request): Promise<Response> {
  const cached = await caches.match(request);
  const fetchPromise = fetch(request).then(async (response) => {
    if (response.ok) {
      const cache = await caches.open(CACHE_NAME);
      cache.put(request, response.clone());
      console.log(`[SW] Revalidated: ${request.url}`);
    }
    return response;
  }).catch(() => cached ?? new Response('Offline', { status: 503 }));

  return cached ?? fetchPromise;
}

async function networkFirst(request: Request): Promise<Response> {
  try {
    const response = await fetch(request);
    if (response.ok) {
      const cache = await caches.open(CACHE_NAME);
      cache.put(request, response.clone());
    }
    return response;
  } catch {
    const cached = await caches.match(request);
    if (cached) {
      console.log(`[SW] Serving from cache (offline): ${request.url}`);
      return cached;
    }
    return new Response('Offline', { status: 503 });
  }
}
```

## Background Sync Manager
```typescript
// src/sync-manager.ts
// Queue mutations for sync when connectivity returns

interface SyncOperation {
  id: string;
  sql: string;
  params: unknown[];
  timestamp: number;
}

const SYNC_STORE = 'frankensqlite-sync-queue';

export async function queueForSync(op: SyncOperation): Promise<void> {
  // Use IndexedDB to persist sync queue (not OPFS — SW can't use SyncAccessHandle)
  const db = await openSyncDB();
  const tx = db.transaction(SYNC_STORE, 'readwrite');
  await tx.objectStore(SYNC_STORE).add(op);
  console.log(`[sync] Queued operation: ${op.id}`);

  // Register for background sync
  if ('sync' in self.registration) {
    await (self.registration as any).sync.register('frankensqlite-sync');
    console.log('[sync] Background sync registered');
  }
}

self.addEventListener('sync', (event: any) => {
  if (event.tag === 'frankensqlite-sync') {
    console.log('[sync] Background sync triggered');
    event.waitUntil(processSyncQueue());
  }
});

async function processSyncQueue(): Promise<void> {
  const db = await openSyncDB();
  const tx = db.transaction(SYNC_STORE, 'readonly');
  const ops = await tx.objectStore(SYNC_STORE).getAll();
  console.log(`[sync] Processing ${ops.length} queued operations`);

  for (const op of ops) {
    try {
      // Send to sync endpoint
      await fetch('/api/sync', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(op),
      });
      // Remove from queue on success
      const deleteTx = db.transaction(SYNC_STORE, 'readwrite');
      await deleteTx.objectStore(SYNC_STORE).delete(op.id);
      console.log(`[sync] Synced: ${op.id}`);
    } catch (err) {
      console.warn(`[sync] Failed to sync ${op.id}, will retry`, err);
      break;  // Stop processing, will retry on next sync event
    }
  }
}
```

## Client Registration Helper
```typescript
// client/register.ts
export async function registerServiceWorker(options?: {
  onUpdate?: () => void;
  scope?: string;
}): Promise<ServiceWorkerRegistration | null> {
  if (!('serviceWorker' in navigator)) {
    console.warn('[SW] Service Workers not supported');
    return null;
  }

  try {
    const registration = await navigator.serviceWorker.register(
      '/sw.js',
      { scope: options?.scope ?? '/' }
    );
    console.log('[SW] Registration successful, scope:', registration.scope);

    // Check for updates
    registration.addEventListener('updatefound', () => {
      const newWorker = registration.installing;
      if (!newWorker) return;

      newWorker.addEventListener('statechange', () => {
        if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
          console.log('[SW] New version available');
          options?.onUpdate?.();
        }
      });
    });

    return registration;
  } catch (err) {
    console.error('[SW] Registration failed:', err);
    return null;
  }
}
